后端注释标准是 moyan-mfw 框架中的编码规范，每个文件必须有 `@fileoverview` 和 `@description`：

```typescript
/**
 * @fileoverview 用户控制器
 * @description 处理用户相关 HTTP 请求
 */

/**
 * 用户控制器
 * @description 处理用户相关的 CRUD 请求
 */
@ApiTags('user', '用户相关接口')
export class UserController {
  /**
   * 创建用户
   */
  @Post()
  async create(@Body() dto: CreateUserDto) { ... }

  /**
   * 根据 ID 查询用户
   * @param id - 用户 ID
   * @returns 用户信息
   */
  async findById(id: string): Promise<User> { ... }
}
```

